// 获取图标颜色
const getIconColor = (iconName: string): string => {
    return iconColors[iconName] || colors.white;
};

// 应用颜色到SVG
const applySvgColor = (svgContent: string, color: string): string => {
    // 如果SVG内容为空，返回默认的文件图标
    if (!svgContent || svgContent.trim() === '') {
        return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32"><path fill="${color}" d="M27.5 4.5H7.5l-3 3v17l3 3h20l3-3v-17l-3-3z"/></svg>`;
    }

    // 如果SVG中已经有fill属性，替换它
    if (svgContent.includes('fill=')) {
        return svgContent.replace(/fill="[^"]*"/g, `fill="${color}"`);
    }

    // 如果SVG中没有fill属性，添加到path标签上
    return svgContent.replace(/<path/g, `<path fill="${color}"`);
};

// 应用尺寸到SVG
const applySvgSize = (svgContent: string, size: number): string => {
    // 如果SVG内容为空，返回默认的文件图标
    if (!svgContent || svgContent.trim() === '') {
        return `<svg xmlns="http://www.w3.org/2000/svg" width="${size}" height="${size}" viewBox="0 0 32 32"><path d="M27.5 4.5H7.5l-3 3v17l3 3h20l3-3v-17l-3-3z"/></svg>`;
    }

    let result = svgContent;

    // 如果没有 viewBox，尝试从原始的 width/height 提取或使用默认值
    if (!result.includes('viewBox=')) {
        const widthMatch = svgContent.match(/width="(\d+)"/);
        const heightMatch = svgContent.match(/height="(\d+)"/);
        const viewBoxWidth = widthMatch ? widthMatch[1] : '32';
        const viewBoxHeight = heightMatch ? heightMatch[1] : '32';
        result = result.replace(/<svg/, `<svg viewBox="0 0 ${viewBoxWidth} ${viewBoxHeight}"`);
    }

    // 替换或添加 width 属性
    if (result.includes('width=')) {
        result = result.replace(/width="[^"]*"/g, `width="${size}"`);
    } else {
        result = result.replace(/<svg/, `<svg width="${size}"`);
    }

    // 替换或添加 height 属性
    if (result.includes('height=')) {
        result = result.replace(/height="[^"]*"/g, `height="${size}"`);
    } else {
        result = result.replace(/<svg/, `<svg height="${size}"`);
    }

    return result;
};

