/**
 * 文件图标组件
 * 根据文件名和类型动态显示对应的SVG图标
 */
const FileIcon: React.FC<FileIconProps> = ({
    fileName,
    isDirectory,
    className = '',
    size = 16
}) => {
    const iconName = getFileIconName(fileName, isDirectory);
    const svgContent = inlineSvgIcons[iconName] || inlineSvgIcons.default;
    const iconColor = getIconColor(iconName);
    const coloredSvg = applySvgColor(svgContent, iconColor);
    if (iconName == 'folder') {
        size = 14
    }
    const finalSvg = applySvgSize(coloredSvg, size);

    return (
        <div
            className={`file-icon ${className}`}
            style={{
                width: size,
                height: size,
                flexShrink: 0,
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
                filter: 'contrast(1.2) saturate(1.1)',
                transform: 'scale(1.1)'
            }}
            dangerouslySetInnerHTML={{ __html: finalSvg }}
        />
    );
};

export default FileIcon;